  void save_ray(double p, int i, double *TOF_N, double *TOF_p, double *TOF_p2) {
	double p2 = p * p;
	#pragma acc atomic
	TOF_N[i] = TOF_N[i] + 1;
	#pragma acc atomic
	TOF_p[i] = TOF_p[i] + p;
	#pragma acc atomic
    TOF_p2[i] = TOF_p2[i] + p2;
  };
		

