  L_N = create_darr1d (nL);
  L_p = create_darr1d (nL);
  L_p2 = create_darr1d (nL);

  // Use instance name for monitor output if no input was given
  if (!strcmp (filename, "\0"))
    sprintf (filename, "%s", NAME_CURRENT_COMP);
